import{_ as a,c as t,o as i,a1 as o}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"更新日誌：版本歷程 | everything-claude-code","description":"了解 everything-claude-code 的版本歷程與重要異動。追蹤新功能、資安修補與文件更新，評估是否需要升級。","frontmatter":{"title":"更新日誌：版本歷程 | everything-claude-code","sidebarTitle":"看看最近更新了什麼","subtitle":"更新日誌：版本歷程","description":"了解 everything-claude-code 的版本歷程與重要異動。追蹤新功能、資安修補與文件更新，評估是否需要升級。","tags":["changelog","updates"],"prerequisite":[],"order":250},"headers":[],"relativePath":"zh-tw/affaan-m/everything-claude-code/changelog/release-notes/index.md","filePath":"zh-tw/affaan-m/everything-claude-code/changelog/release-notes/index.md"}'),l={name:"zh-tw/affaan-m/everything-claude-code/changelog/release-notes/index.md"};function r(d,e,n,s,h,c){return i(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="更新日誌-版本歷程與異動" tabindex="-1">更新日誌：版本歷程與異動 <a class="header-anchor" href="#更新日誌-版本歷程與異動" aria-label="Permalink to &quot;更新日誌：版本歷程與異動&quot;">​</a></h1><h2 id="學完你能做什麼" tabindex="-1">學完你能做什麼 <a class="header-anchor" href="#學完你能做什麼" aria-label="Permalink to &quot;學完你能做什麼&quot;">​</a></h2><ul><li>了解每個版本的重要異動</li><li>追蹤新功能和修補項目</li><li>評估是否需要升級</li></ul><h2 id="版本歷程" tabindex="-1">版本歷程 <a class="header-anchor" href="#版本歷程" aria-label="Permalink to &quot;版本歷程&quot;">​</a></h2><h3 id="_2026-01-24-資安修補與文件修正" tabindex="-1">2026-01-24 - 資安修補與文件修正 <a class="header-anchor" href="#_2026-01-24-資安修補與文件修正" aria-label="Permalink to &quot;2026-01-24 - 資安修補與文件修正&quot;">​</a></h3><p><strong>修補內容</strong>：</p><ul><li>🔒 <strong>資安修補</strong>：防止 <code>commandExists()</code> 中的指令注入弱點 <ul><li>使用 <code>spawnSync</code> 取代 <code>execSync</code></li><li>驗證輸入僅允許英數字元、連字號、底線、句點</li></ul></li><li>📝 <strong>文件修正</strong>：新增 <code>runCommand()</code> 的資安文件警語</li><li>🐛 <strong>XSS 掃描器誤判修正</strong>：將 <code>&lt;script&gt;</code> 和 <code>&lt;binary&gt;</code> 替換為 <code>[script-name]</code> 和 <code>[binary-name]</code></li><li>📚 <strong>文件修正</strong>：修正 <code>doc-updater.md</code> 中的 <code>npx ts-morph</code> 為正確的 <code>npx tsx scripts/codemaps/generate.ts</code></li></ul><p><strong>影響</strong>：#42, #43, #51</p><hr><h3 id="_2026-01-22-跨平台支援與外掛化" tabindex="-1">2026-01-22 - 跨平台支援與外掛化 <a class="header-anchor" href="#_2026-01-22-跨平台支援與外掛化" aria-label="Permalink to &quot;2026-01-22 - 跨平台支援與外掛化&quot;">​</a></h3><p><strong>新功能</strong>：</p><ul><li>🌐 <strong>跨平台支援</strong>：所有 hooks 和指令稿重寫為 Node.js，支援 Windows、macOS 和 Linux</li><li>📦 <strong>外掛封裝</strong>：以 Claude Code 外掛形式發布，支援外掛市集安裝</li><li>🎯 <strong>套件管理器自動偵測</strong>：支援 6 種偵測優先順序 <ul><li>環境變數 <code>CLAUDE_PACKAGE_MANAGER</code></li><li>專案組態 <code>.claude/package-manager.json</code></li><li><code>package.json</code> 的 <code>packageManager</code> 欄位</li><li>Lock 檔偵測（package-lock.json, yarn.lock, pnpm-lock.yaml, bun.lockb）</li><li>全域組態 <code>~/.claude/package-manager.json</code></li><li>降級至第一個可用的套件管理器</li></ul></li></ul><p><strong>修補內容</strong>：</p><ul><li>🔄 <strong>Hook 載入</strong>：自動依慣例載入 hooks，移除 <code>plugin.json</code> 中的 hooks 宣告</li><li>📌 <strong>Hook 路徑</strong>：使用 <code>${CLAUDE_PLUGIN_ROOT}</code> 與相對路徑</li><li>🎨 <strong>介面改善</strong>：新增 star 歷程圖表與 badge bar</li><li>📖 <strong>Hook 整理</strong>：將 session-end hooks 從 Stop 移至 SessionEnd</li></ul><hr><h3 id="_2026-01-20-功能強化" tabindex="-1">2026-01-20 - 功能強化 <a class="header-anchor" href="#_2026-01-20-功能強化" aria-label="Permalink to &quot;2026-01-20 - 功能強化&quot;">​</a></h3><p><strong>新功能</strong>：</p><ul><li>💾 <strong>Memory Persistence Hooks</strong>：跨工作階段自動儲存與載入上下文</li><li>🧠 <strong>Strategic Compact Hook</strong>：智慧型上下文壓縮建議</li><li>📚 <strong>Continuous Learning Skill</strong>：從工作階段中自動萃取可重複使用的模式</li><li>🎯 <strong>Strategic Compact Skill</strong>：Token 最佳化策略</li></ul><hr><h3 id="_2026-01-17-首次發布" tabindex="-1">2026-01-17 - 首次發布 <a class="header-anchor" href="#_2026-01-17-首次發布" aria-label="Permalink to &quot;2026-01-17 - 首次發布&quot;">​</a></h3><p><strong>初始功能</strong>：</p><ul><li>✨ 完整的 Claude Code 組態集合</li><li>🤖 9 個專業化 agents</li><li>⚡ 14 個斜線指令</li><li>📋 8 套規則集</li><li>🔄 自動化 hooks</li><li>🎨 11 個技能庫</li><li>🌐 15+ 個 MCP 伺服器預設組態</li><li>📖 完整的 README 文件</li></ul><hr><h2 id="版本命名說明" tabindex="-1">版本命名說明 <a class="header-anchor" href="#版本命名說明" aria-label="Permalink to &quot;版本命名說明&quot;">​</a></h2><p>本專案不使用傳統的語意化版本號，而是採用<strong>日期版本</strong>格式（<code>YYYY-MM-DD</code>）。</p><h3 id="版本類型" tabindex="-1">版本類型 <a class="header-anchor" href="#版本類型" aria-label="Permalink to &quot;版本類型&quot;">​</a></h3><table tabindex="0"><thead><tr><th>類型</th><th>說明</th><th>範例</th></tr></thead><tbody><tr><td><strong>新功能</strong></td><td>新增功能或重大改善</td><td><code>feat: add new agent</code></td></tr><tr><td><strong>修補</strong></td><td>修正 bug 或問題</td><td><code>fix: resolve hook loading issue</code></td></tr><tr><td><strong>文件</strong></td><td>文件更新</td><td><code>docs: update README</code></td></tr><tr><td><strong>樣式</strong></td><td>格式化或程式碼風格</td><td><code>style: fix indentation</code></td></tr><tr><td><strong>重構</strong></td><td>程式碼重構</td><td><code>refactor: simplify hook logic</code></td></tr><tr><td><strong>效能</strong></td><td>效能最佳化</td><td><code>perf: improve context loading</code></td></tr><tr><td><strong>測試</strong></td><td>測試相關</td><td><code>test: add unit tests</code></td></tr><tr><td><strong>建置</strong></td><td>建置系統或相依套件</td><td><code>build: update package.json</code></td></tr><tr><td><strong>復原</strong></td><td>復原先前的提交</td><td><code>revert: remove version field</code></td></tr></tbody></table><hr><h2 id="如何取得更新" tabindex="-1">如何取得更新 <a class="header-anchor" href="#如何取得更新" aria-label="Permalink to &quot;如何取得更新&quot;">​</a></h2><h3 id="外掛市集更新" tabindex="-1">外掛市集更新 <a class="header-anchor" href="#外掛市集更新" aria-label="Permalink to &quot;外掛市集更新&quot;">​</a></h3><p>如果你透過外掛市集安裝了 Everything Claude Code：</p><ol><li>開啟 Claude Code</li><li>執行 <code>/plugin update everything-claude-code</code></li><li>等待更新完成</li></ol><h3 id="手動更新" tabindex="-1">手動更新 <a class="header-anchor" href="#手動更新" aria-label="Permalink to &quot;手動更新&quot;">​</a></h3><p>如果你手動複製了儲存庫：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.claude/plugins/everything-claude-code</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pull</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main</span></span></code></pre></div><h3 id="從市集安裝" tabindex="-1">從市集安裝 <a class="header-anchor" href="#從市集安裝" aria-label="Permalink to &quot;從市集安裝&quot;">​</a></h3><p>首次安裝：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/plugin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> marketplace</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> affaan-m/everything-claude-code</span></span></code></pre></div><hr><h2 id="異動影響分析" tabindex="-1">異動影響分析 <a class="header-anchor" href="#異動影響分析" aria-label="Permalink to &quot;異動影響分析&quot;">​</a></h2><h3 id="資安修補-必須升級" tabindex="-1">資安修補（必須升級） <a class="header-anchor" href="#資安修補-必須升級" aria-label="Permalink to &quot;資安修補（必須升級）&quot;">​</a></h3><ul><li><strong>2026-01-24</strong>：指令注入弱點修補，強烈建議升級</li></ul><h3 id="功能強化-選擇性升級" tabindex="-1">功能強化（選擇性升級） <a class="header-anchor" href="#功能強化-選擇性升級" aria-label="Permalink to &quot;功能強化（選擇性升級）&quot;">​</a></h3><ul><li><strong>2026-01-22</strong>：跨平台支援，Windows 使用者必須升級</li><li><strong>2026-01-20</strong>：新功能強化，依需求升級</li></ul><h3 id="文件更新-無需升級" tabindex="-1">文件更新（無需升級） <a class="header-anchor" href="#文件更新-無需升級" aria-label="Permalink to &quot;文件更新（無需升級）&quot;">​</a></h3><ul><li>文件更新不影響功能，可手動查閱 README</li></ul><hr><h2 id="已知問題" tabindex="-1">已知問題 <a class="header-anchor" href="#已知問題" aria-label="Permalink to &quot;已知問題&quot;">​</a></h2><h3 id="目前版本-2026-01-24" tabindex="-1">目前版本（2026-01-24） <a class="header-anchor" href="#目前版本-2026-01-24" aria-label="Permalink to &quot;目前版本（2026-01-24）&quot;">​</a></h3><ul><li>無已知嚴重問題</li></ul><h3 id="先前版本" tabindex="-1">先前版本 <a class="header-anchor" href="#先前版本" aria-label="Permalink to &quot;先前版本&quot;">​</a></h3><ul><li>2026-01-22 之前：Hooks 載入需要手動組態（已於 2026-01-22 修正）</li><li>2026-01-20 之前：不支援 Windows（已於 2026-01-22 修正）</li></ul><hr><h2 id="貢獻與意見回饋" tabindex="-1">貢獻與意見回饋 <a class="header-anchor" href="#貢獻與意見回饋" aria-label="Permalink to &quot;貢獻與意見回饋&quot;">​</a></h2><h3 id="回報問題" tabindex="-1">回報問題 <a class="header-anchor" href="#回報問題" aria-label="Permalink to &quot;回報問題&quot;">​</a></h3><p>如果你發現了 bug 或有功能建議，請：</p><ol><li>在 <a href="https://github.com/affaan-m/everything-claude-code/issues" target="_blank" rel="noreferrer">GitHub Issues</a> 搜尋是否已有類似問題</li><li>如果沒有，建立新 Issue，並提供： <ul><li>版本資訊</li><li>作業系統</li><li>重現步驟</li><li>預期行為 vs 實際行為</li></ul></li></ol><h3 id="提交-pr" tabindex="-1">提交 PR <a class="header-anchor" href="#提交-pr" aria-label="Permalink to &quot;提交 PR&quot;">​</a></h3><p>歡迎貢獻！請參閱 <a href="https://github.com/affaan-m/everything-claude-code/blob/main/CONTRIBUTING.md" target="_blank" rel="noreferrer">CONTRIBUTING.md</a> 了解詳情。</p><hr><h2 id="本課小結" tabindex="-1">本課小結 <a class="header-anchor" href="#本課小結" aria-label="Permalink to &quot;本課小結&quot;">​</a></h2><ul><li>Everything Claude Code 使用日期版本號（<code>YYYY-MM-DD</code>）</li><li>資安修補（如 2026-01-24）必須升級</li><li>功能強化可依需求升級</li><li>外掛市集使用者使用 <code>/plugin update</code> 更新</li><li>手動安裝使用者使用 <code>git pull</code> 更新</li><li>回報問題與提交 PR 請遵循專案指南</li></ul><h2 id="下一課預告" tabindex="-1">下一課預告 <a class="header-anchor" href="#下一課預告" aria-label="Permalink to &quot;下一課預告&quot;">​</a></h2><blockquote><p>下一課我們學習 <strong><a href="./../../appendix/config-reference/">組態檔詳解</a></strong>。</p><p>你會學到：</p><ul><li><code>settings.json</code> 的完整欄位說明</li><li>Hooks 組態的進階選項</li><li>MCP 伺服器組態詳解</li><li>自訂組態的最佳實務</li></ul></blockquote>',64)])])}const p=a(l,[["render",r]]);export{u as __pageData,p as default};
